import{_ as b,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"怪盗","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/5.通用类/怪盗.md","filePath":"4.资源分区/1.血统与训练/5.通用类/怪盗.md"}'),s={name:"4.资源分区/1.血统与训练/5.通用类/怪盗.md"};function o(d,p,A,l,C,E){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"怪盗",tabindex:"-1"},[t("怪盗 "),r("a",{class:"header-anchor",href:"#怪盗","aria-label":'Permalink to "怪盗"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序009")])])],-1),n('<h1 id="怪盗-1" tabindex="-1">怪盗 <a class="header-anchor" href="#怪盗-1" aria-label="Permalink to &quot;怪盗&quot;">​</a></h1><p>怪盗</p><p>前提：敏捷5 决心5 风度5 操控5 隐秘3：潜藏3</p><p>D级：<br> 特性：怪盗风格、隐匿无踪、声名渐起<br> 怪盗风格：身为一名怪盗，自然得拥有怪盗的行事风格，虽然每一名怪盗都有着自己的特色，但是也一些共同点。首先是准备一套甚至是多套的怪盗服，怪盗服必须得是一套方便行动且极具怪盗个人风格的服装，让人能明确知道你那位怪盗。然后就是在选择一个盗取目标或者行动目标后会提前发出预告信，预告信明确或者隐晦地表明你的行动时间、目标、怪盗身份。最后就是在行动完成后留下独属你个人标记，包括但不限于花、信、涂鸦。<br> 隐匿无踪：在判断一名怪盗是属于什么级别的时候，其隐蔽行动能力是最为重要的一项，一名合格的怪盗在发出预告信前是绝对不会被发现。因此一名怪盗能通过合理的观察并利用地形在视线死角中隐蔽行动，并且不会留下任何线索，这可以视为等于训练等级的自然本质的反侦察等级。这种反侦察能力实际上只是一只技巧的运用，因此在被他人模糊定位或者精确定位后这一反侦测等级会在一场景内失效。如果怪盗获得基于潜意识而觉醒的人格面具能力，那么他将自身怪盗这属性与世人潜意识中的印象强化到极致-[怪盗在达成目的前是绝对不会被发现的印象]，也因此这一能力不会因为被模糊定位或者精确定位而失效。<br> 声名渐起：随着怪盗行动不断的达成，怪盗身份的事迹与名声开始传播开了，每完成一次完整的怪盗行动后（通常是一影片），怪盗身份的声望会因为这些事迹获得6点提升。</p><p>C级：<br> 特性：隐形冲刺、巧手、潜入道具制作<br> 隐形冲刺：在进行怪盗行动中最重要的就是保持隐蔽的同时快速行动 ，于是在行动中不发出任何声音就成为了基本功之一，即便是快速奔跑也能不发出声音，也不会影响潜行行动。这意味着怪盗可以在潜行时进行全速移动。<br> 巧手：作为一名怪盗，为了面对各种机关、陷阱、门锁，练就了一双巧手。普通人无论多么敏捷，也只能快速耍一个花招，而怪盗的巧手则是随着身体敏捷提升，就能耍越多的花招。这意味着怪盗在回合开始时获得1点AP，这种AP只能用于手部动作。<br> 潜入道具制作：随着目标变更，光是靠潜行和伪装已经是不够了，开始需要配合各种道具辅助潜入。怪盗已经开始学会制作一些简单的潜入道具，同时也有渠道购买到成品潜入道具。</p><p>B级：<br> 特性：魔术手、第三只眼<br> 魔术手：原本的一双巧手随着不断的训练，已经如同魔术师的手一样灵活迅捷，取代原本巧手的效果，怪盗现在每轮开始时会获得【敏捷附加】点AP，这种AP只能用于手部动作。<br> 第三只眼：随着训练等级提升，为了更好的挑选目标与破除陷阱，怪盗已经培养出几乎是特异功能一样直觉。怪盗能够不加思索判断那些物品是有价值、那些东西是有价值的线索、陷阱极品的解除方式，这可以视为一种强感知方式，具有等于训练等级的自然本质的侦测等级。</p><p>A级：<br> 特性：灵动优雅、单跳回避、声名远扬<br> 灵动优雅：不同的怪盗有着不同的风格，特别是行动中的动作，往往是灵活并且优雅的。接受本级训练前需要先选择一种运动方式作为专精方向，包括但不限于舞蹈、艺术体操、格斗术等，无论如何这种运动方式具有灵活、优雅两种特点。所选运动方式会成为一种特殊的运动专业，该专业永远等于运动技能等级，同时能直接加入任何运动和武技相关检定，因为怪盗将这种运动方式与行动时一举一动结合起来，唯一需要注意的是在以怪盗以外身份行动时，如果也用这种行动方式别人能直接推断出你的怪盗身份。并且因为接受过这种针对运动方式的训练方式，怪盗在每轮开始时再获得6点AP以将移动动作升级为杂技动作。<br> 单跳回避：怪盗那份特异功能一样直觉已经随着训练等级提升变得更加敏感了，即便是面对任何危机都能快速反应过来并躲避。这意味你在面对任何被发觉到的危机，都能在其来袭之前调用任意动作来进行移动躲避，并且可以结合移动类技艺在其中。这可以视为等于一种等于训练等级的免措手不及能力。<br> 声名远扬：对比才开始受训时青涩表现，如今的怪盗已经能熟练的完成每一次行动，让人不得不更加谨慎的对待。取代声名渐起的提升速度，现在每完成一次完整的怪盗行动后（通常是一影片），怪盗身份的声望会因为这些事迹获得20点提升。</p><p>S级：<br> 特性：完美隐秘、无限可能<br> 完美隐秘:虽然有无数的人在攀登各种技艺的巅峰，但是将已经掌握的技艺能完全运用的人却在少数，对于这种境界有很多称呼，无缺、超凡、完美…。而完成训练的怪盗就在隐秘这一道到达这一境界，即便是在隐秘上获得任何提升也能第一时间掌握，因为任何的失误都可能导致行动失败，所以一名合格的怪盗应该达到这个境界。每轮一次，在进行任何隐秘相关检定时全骰直接成功但是无加骰。<br> 无限可能：怪盗的训练已然结束，但是怪盗的可能性才刚开始绽放。或许会像阿里巴巴和四十大盗一样，从恶人的宝库中盗取财宝。或许会像勇者斗恶龙一样，从恶龙的牢笼中盗取公主后再顺便盗取公主的芳心。但怪盗的可能性才刚开始。或许会像普罗米修斯盗火一样，为众生盗取名为未来的火种。为了支撑起这无限的可能，必须得打好无比扎实的基础，因此怪盗训练的最后一部分是一套自学方法，从五个方面加强自身。从日常点点滴滴获得隐形的成长，这些成长会不断累计下来，直到抽空进行一次总结回顾的时候便能得知在那些方面获得了成长。通常情况下 完成一次同级别偷盗（例如偷取同级别单位的心让他悔过）能让某一方面获得♪×4的提升，而一次完整经历能让某一方面获得♪×25的提升。每个方面都是每累积50♪提升一个阶段，每个方面在没有达到第一阶段前都视为没有入门的零级。（经历=影片或者类似的情况，完整的经历是指在这次经历中没有提前总结回顾获得成长）<br> 知识：一切关于获取新知识、考验旧知识、认真思考的行为都能使知识方面获得成长。知识阶段代表着怪盗对各种已接触过事物与知识的了解与研究程度，当到达第一阶段后意味着怪盗对任何事务都有所了解，在学识下任何专业进行检定时都将获得知识阶段×智力的加值，并且视为具有所有学识下所有专业。<br> 知识阶段：1、才疏学浅 2、勤奋好学 3、知识分子 4、博学多闻 5+、智慧之泉<br> 勇气：一切关于坚定决心、鼓起勇气、进行挑战的行为都能使勇气方面获得成长。勇气阶段代表着怪盗的意志坚韧程度，当到达第一阶段后意味着怪盗的意志已经坚韧到可以抵御各种影响心灵能力，在进行决心相关检定时获得【勇气阶段×决心】的加值，并且免疫阶段等级+2的心灵来源负面效果。（B、A、S、SS…）<br> 勇气阶段：1、胆小多疑 2、独当一面 3、不屈不饶 4、大胆无畏 5+、狮王之心<br> 魅力：一切关于培养气质、提高情商、吸引异性的行为都能使魅力方面获得成长。魅力阶段代表着怪盗的容貌与气质结合后对他人的吸引力程度，当到达第一阶段后意味着怪盗的外貌配合气质已经达到超自然能力中魅惑术的程度，怪盗的外貌提升【魅力阶段×风度】的数值，并且怪盗的攻击在命中后会附加【魅力阶段*2】点不可豁免的魅惑异常点。<br> 魅力阶段：1、一般程度 2、令人在意 3、潜力十足 4、魅力洋溢 5+、魔性之人<br> 灵巧：一切关于精细操作、锻炼反应力、锻炼速度的行为都能使灵巧方面获得成长。灵巧阶段代表着怪盗的反应速度、动作精准程度、动作速度这三个方面的程度，当到达第一阶段后意味着怪盗的动作像机器一样精准快速，在进行敏捷相关检定获得【灵巧阶段×敏捷】的加值，并且获得等于【灵巧阶段×3】点AP。（敏捷提升灵巧×敏捷，操控提升灵巧×操控）<br> 灵巧阶段：1、笨手笨脚 2、普普通通 3、专业职人 4、大师手艺 5+、魔术大师<br> 体贴：一切关于基于善意的行动、照顾动植物、关心帮助他人的行为都能使体贴方面获得成长。体贴阶代表着怪盗的善良程度与他人相处方法的掌握，当到达第一阶段后意味着任何人都愿意与怪盗相处结识，在进行社交/表达（购买时选择）相关检定获得【体贴阶段×操控】的加值，怪盗的声望提升【体贴阶段*50】点。<br> 体贴阶段：1、不甚关心 2、倾听高手 3、善解人意 4、乐于助人 5+、圣母慈爱<br> 特殊的，由这方面是基于心灵方面的提升，允许替换成符合怪盗特色的心灵方面其它方向提升，其加值方向也替换成符合怪盗特色的其它技能。</p><p>—专属专长：基于怪盗技艺发展的专长，只有接受过怪盗训练的人才能锻炼出怪盗的专属专长。</p><p>声拟万物（2）<br> 前提：一人千面、拥有某种超能力<br> 现在只需要一个花招动作就能够无材料伪装，并且能够伪装体积误差在1的目标，除此之外还利用超能力发出各种声音，包括类人生物、动物、风声、开门声等。</p><p>怪盗宝库（2）<br> 前提：隐蔽盗宝、魔术手、拥有某种超能力<br> 如同将战备武装2级效果运用到盗取动作上，怪盗可以以花招动作偷取目标随身携带的武器。怪盗可以从目标腰包或背包中偷取物品下降为一个移动动作，从目标衣袋内取东西是一个迅捷动作。除此之外，可以将被盗取物品收纳进由超能力构筑的四次元藏宝室，藏宝室大小为100立方米左右。</p><p>怪盗技能树：怪盗的各种技艺，按照个人特色和行动习惯不同，每一面怪盗所擅长的技艺均不同，但是怪盗训练还是收录和提供了这些技艺的学习方法。</p><p>—潜入类：<br> D级：一人千面<br> 为了混入各式各样的场所，以及为了伪装平常的身份，怪盗得精通各种伪装技巧。本技艺包含了各种伪装技巧和观察伪装目标的方法，并且额外提到有超能力后怎样能更加快速的伪装他人。怪盗习得本技艺后，能够完美的伪装自己所了解的人，包括声音、行为习惯、服饰等，这一切都是基于观察他人获得的信息。侦察、察言观色、行为分析等检定都能增加怪盗对被伪装者的了解，依靠这些信息怪盗能在10分钟左右的时间完成对一次伪装。伪装只需要学习技艺时附送的伪装材料就能完成，但是受体型限制，无法伪装体积不同的目标,。</p><p>B级：隐蔽盗宝<br> 在怪盗发完预告信后，总有些人选择会选择贴身携带来保护宝物，但是这是无法阻止怪盗在其未发觉的时候将宝物盗走。学习本技艺后，怪盗习得从他人身上直接盗取物品的技巧，盗取动作根据物品位置不同需要不同的动作，基本等于从自身相应位置取出物品的动作。盗取需要怪盗以盗窃检定对抗目标反射豁免+物品等级（D14/C26/B38/A48/S66），当盗取失败时需要以掩饰检定对抗目标的侦察检定成功才能不被发现。如果怪盗拥有超自然的能力时，还能永久获得不超过训练等级宝物的所有权并带走的能力，这视为等于怪盗训练等级的夺权能力。</p><p>—战斗类：<br> B级：CHANCE!!（B+3000）<br> 在进行怪盗行动的时候，总会有遇上必须解决的守卫。虽然不同怪盗有着不同的解决办法，但是都有一个共同点，在无人发现的情况下快速解决，包括那名守卫。本技艺实际上是包含各种偷袭方法的通用技巧，能完美融合到不同的怪盗风格当中。学习本技艺后，怪盗学会在各种地形行动与偷袭的方法。被偷袭的目标在没有发现隐蔽状态或者伪装状态的怪盗情况下，往往无法反应过来，在这种情况下展开的战斗中，敌人会因为完全失去局势把控而无法应对怪盗的攻击，并且怪盗能更快的做出反应，在先攻上会获得等于敏捷数值的加值，这视为等于训练等级的措手不及攻击技巧。</p><p>B级：锁链勾绳<br> 前提：CHANCE!!、勾绳<br> 在学会CHANCE!!的基础上，将勾绳作为突进手段的进阶技巧，仅在以CHANCE!!为基础展开的战斗中的第一轮或突袭轮中，以一个标准动作进行一次杂技移动，这次移动是以勾绳作为主要移动手段，并且是以敌人作为抓钩投掷目标，在突进移动的同时攻击敌人的弱点，如果有多个敌人就进行依次突进并攻击多次次。然后根据不同怪盗的战斗风格，可以自由选择一种普通攻击方式加入其中，根据攻击形式不同正常防御或者豁免。同时敌人需要以伤害数作为DC依次进行强韧豁免、意志豁免、反射豁免，当强韧豁免未通过会陷入昏迷状态，当意志豁免未通过通过会陷入惊惧状态，当反射豁免未通过会陷入无法分辨敌我的混乱状态，三种异常状态只会出现最先未被豁免一种，且都只持续一轮，视为为A级昏迷、A级惊惧、B级混乱效果。</p><p>怪盗团简易训练：很少有人是全能，怪盗也不例外，全能的怪盗可谓是少之又少。因此有部分怪盗会选择招集同伴成立怪盗团。让同伴完成怪盗单独完成本来的事，虽然诸如远程计算支持的黑客、观察情况的眼线、驾驶载具的接应等一系列人才都是怪盗行动中所需要的支持，但是每一名加入怪盗团的成员都需要接受来着怪盗的简单训练后才能配合怪盗行动。这些训练项目只需要怪盗习得后就能无条件训练他人，每项训练都不需要过多的时间，根据人的天赋完成时间从半天到一星期不等。这种训练是不占用血统和训练位。</p><p>C级：基础训练—隐匿跟随（C+2000）<br> 本训练包含隐蔽技巧快速入门的技巧和多套无声沟通的方法，同时本训练也是之后所有训练的基础。接受训练后的团员至少能在怪盗带领下进入于隐匿无踪相同的隐蔽状态，这种隐蔽状态只能在怪盗身边20米内保持，这视为等于隐匿无踪等级和本质反侦察能力。如果怪盗能进行隐形冲刺，那么团员也能一同不受潜行行走速度减半的限制。</p><p>D级：支援训练—专属座驾<br> 前提：基础训练—隐蔽跟随、怪盗训练C级<br> 本训练包含多种载具改造方法，只能由具有载具制造专业相关的团员接受。接受训练后的团员能与怪盗一起对任意机械类载具进行改造，改造时间等于载具等级的制作时间。被改造后的载具会具有一个和怪盗绑定的特殊形态，这种特殊形态只会在怪盗乘坐或驾驶的时候以一个花招动作开启。特殊形态下的载具与平常外观不同，外观颜色和部分造型细节都会变得具有怪盗风格。除了外观变更以外，载具的最高速度还将提高30米，同时还会具有不受速度限制的反侦察行动能力，其等级和本质等于隐匿无踪。特殊的是如果怪盗具有超能力还能对生物类载具进行改造，但此时则是需要动物驯服相关专业的团员。</p><p>A级：追击训练—MORE<br> 为了快速解决敌人而存在的训练项目，本训练内容由两部分组成，第一部分是当敌人陷入异常后继续行动追击，第二部分是当力竭后与同伴换手，接受训练后的怪盗和团员能在战斗中通过配合在必要的时候由一人再次行动一次，这便是MORE。怪盗或团员在战斗中使用任何手段使任意一名敌人陷入异常或者获得异常点时，便能触发MORE效果，可以立即进行一次不超过标准动作的行动。并且在触发MORE时周围有任意同样接受过训练的同伴，能花招动作进行一次击掌表示换手，将这次MORE效果转移给他，转移后的MORE效果获得的动作不能使用招式，这之后其无法再将MORE效果转移。一个角色每轮只能触发一次MORE效果。</p><p>A级：配合训练—SHOW TIME（好戏上场）<br> 前提：追击训练—MORE<br> 本训练是基于一种名为星石的特殊物品，两名有一定羁绊的团员或团长在星石旁边讨论联手配合的内容时，星石就能将两人之间的羁绊变实质的力量，使其在MORE触发同时一同触发SHOWTIME。 因此与其他训练不同，只能由固定的两人进行配合，并且由这两人分别支付学星石的花费（即双方皆花费A+4000）。相应的，不同两人组都能再强化一场，这意味一人能多次进行这个训练，但是一次MORE只能触发一次SHOWTIME。<br> SHOWTIME效果是根据购买时所讨论的内容所决定的，两人分别获得12点AP，并拟定这12点AP的使用方式。此后当这两人中有一人触发MORE效果且另外一人在场的时候，便能在MORE效果前触发一次SHOW TIME效果，两人会按照先前拟定的动作进行行动。并且在两人行动结束前场景会进入一种S级幻象来源的伪时间停止状态，触发MORE的敌方单位会一起进入这种伪时停状态。并且在场的其他人还会看到以这两人为中心的幻像，这些幻像并不会有任何实际的影响，只会使两人动作产生的效果变成一场华丽的表演，表演效果一般为两人之间羁绊的画风，在行动结束后伪时停和幻想都会消失，并继续进行MORE效果。</p><p>潜入道具：本系列的物品均是以【手艺—潜入道具】作为制作专业，同时怪盗也有渠道直接购买潜入道具与材料，通常情况下潜入道具只能由接受过怪盗训练的人使用。如无特殊说明对应等级的潜入道具购买价格为D+500/C+1000/B+2000/A+4000/S+8000，而对应等级的制造材料价格为1750/D+1500/C+3000/B+6000/A+12000。<br> C级：勾绳<br> 怪盗改造后攀爬工具，是一种贴合在手腕上的隐蔽道具，经过外观伪装后能伪装成皮肤。道具内可拔出一根可以自由控制展开收缩的小型抓钩，抓钩尾端连着坚韧透明的丝绳，丝绳能够承受怪盗十倍的重量。而连接丝绳的内部机构上，虽然为了隐蔽性没有发射装置，需要怪盗自己投掷出去，但是在不影响隐蔽性的情况下强化了收绳装置的速度，不论多远的距离都能在极短的时间内收回。怪盗在使用勾绳移动时分为两种用法，一种是只需要一个花招动作就能完成的直线移动，但是受怪盗基础素质限制，每次只能将抓钩投掷出（力量+敏捷+运动）米。另一种是结合在任意移动过程中，在第一种用法的基础上，在空中提前收回钩爪并再次抛出，在环境合适的情况能提供近乎飞行的机动性，但一样受怪盗基础素质限制，每次只能将抓钩投掷出（力量+敏捷+运动）米。同时因为使用限制，无论那种使用方式都必须有一只手空出来抛钩才能使用勾绳。</p><p>D+级：开锁工具<br> 一套便携的一次性开锁工具，体积为0.1，能打开等于材料等级及以下的锁，使用后消耗掉。开锁工具在怪盗没有超自然能力的时候只能开启纯粹机械结构的锁，但是怪盗如果拥有超自然能力则能开启电子锁或是魔法锁，同时怪盗的伙伴有超能力的时候也能在怪盗指挥下使用。如果涉及需要对抗的情况用【操控：隐秘—开锁】进行对抗。在制造的开锁工具时候，不同等级的材料产出数量是不同的，分别为15/15/20/25/30把。<br> （例：如果怪盗获得基于潜意识而觉醒的人格面具能力，那么他将能直接打开基于怪盗认知上的锁。如果获得魔法类的能力，则能直接打开结界之类魔法。如果获得科技侧能力，则能将开锁工具作为一次性骇入工具。）</p><p>D+级：无限开锁工具<br> 开锁工具升级版，不会因为使用而被消耗掉，同时在原本打开等于材料等级及以下的锁的基础上，怪盗能在他人帮助下将各种超自然能力记录在无限开锁工具内，并永久拥有开启对应类型的锁或者概念上的锁的能力，在C级及以下等级材料只能记录6种，而B级及以上等级材料则不受限制。由A级、S级材料制造出来的无限开锁工具还额外具有其它效果，由A级材料制造出来的无限开锁工具具有对被解锁事物短时间支配效果，能通过暂时放弃开锁来对一个事物进行长时间支配。而由S级材料制造出来的无限开锁工具不仅将支配时间提高到十五分钟，而且能同时对半径600米的事物进行开锁和支配。这些支配效果均等于材料等级。</p><p>C~B级：烟幕<br> 烟幕是体积为0.1的小型烟雾弹，能够持续释放烟雾遮挡他人视线，烟雾的颜色和形状可以通过制作时或者购买时定制，而烟幕触发方式一共有三种，受到一定程度的外力的触发、定时触发、遥控触发，无论那种方式都只能由怪盗以一个花招动作触发。烟幕能持续释放烟雾15分钟，这个时间可以由怪盗远程控制而提前结束。在观察烟雾内部情况时，视为等于隐匿无踪等级和本质的反侦察效果，需要对抗的时候则由烟雾内每个单位单独对抗，而由于材料等级的不同，烟幕的遥控范围与生效范围也不同的，遥控范围与生效范围都是半径210/480米的球形范围，即便是定制了形状也不会超过这个球形范围。</p><p>A~S级：催眠迷雾（附带不限量的解药）<br> 催眠迷雾是基于烟幕的变种，体积相同、触发方式相同，但是从原本一次性消耗品变成可回收的道具，回收后需要再进行一次制造的延迟检定进行填充才能再次使用，并且原本的烟雾变成无色的催眠气体，除了提前服下解药的怪盗及其同伴以外，所有需要呼吸的生物均会受到影响进入睡眠状态一天，除非进行进行强韧豁免对抗制作或者填充催眠迷雾时的成功数成功，或者受到外力严重影响而被唤醒，这是等于催眠迷雾等级的睡眠异常效果。催眠迷雾能持续释放气体15分钟，这个时间可以由怪盗远程控制而提前结束。而催眠迷雾的遥控范围与生效范围也变成了半径240/4200米的球形范围。如果怪盗拥有超自然的能力时，可以选择一种加入到催眠迷雾的制作当中，并拥有更强的渗透性和作用范围，通常能使一些没有睡眠概念的存在也进入睡眠状态。（比如机器人、AI程序、魔像等）</p><p>—能量伤害套装：能照成不同类型伤害的九种小型炸弹，分别为米吉多炸弹、汽油弹、冻结喷雾、电击棒、空气炮、精神炸弹、原子火柴、红色炸弹、诅咒炸弹，这些炸弹体积都为1，使用方式都是直接丢出去接触到目标后造成能量伤害，如果目标在一定范围内只需要一个花招动作就能丢出，超出这个距离的都需要进行投掷动作，特殊的是除了米吉多炸弹能造成大范围群体伤害，其他八种都是只能造成单体伤害。<br> C+级：米吉多炸弹<br> 能造成万能属性伤害的小型炸弹，万能属性伤害是能无视属性抗性的混合伤害，只要不是全伤害类型都具有免疫的目标就会受到这个伤害，在使用的是以一个目标为中心造成一个球形范围伤害，而花招使用的距离中心目标距离计算的。根据材料等级不同，花招使用射程分别为35/65/165/615米，伤害范围分别为半径20/50/120/400米的球形范围，造成伤害量分别为11/24/95/235点不可豁免的万能伤害。</p><p>C+级：汽油弹<br> 能造成火焰属性伤害的小型炸弹，同时附带等于伤害量的不可豁免的燃烧异常点。根据材料等级不同，花招使用射程分别为100/130/200/1000米，造成伤害量分别为5/11/25/103点不可豁免的火焰伤害。</p><p>C+级：冻结喷雾<br> 能造成冰冻属性伤害的小型炸弹，同时附带等于伤害量的不可豁免的冻结异常点。根据材料等级不同，花招使用射程分别为90/120/240/600米，造成伤害量分别为6/13/29/59点不可豁免的寒冰伤害。</p><p>C+级：电击棒<br> 能造成电击属性伤害的小型炸弹，同时附带等于伤害量的不可豁免的麻痹异常点。根据材料等级不同，花招使用射程分别为90/120/240/600米，造成伤害量分别为6/13/29/59点不可豁免的雷电伤害。</p><p>D+级：空气炮<br> 能造成疾风属性伤害的小型炸弹。根据材料等级不同，花招使用射程分别为45/90/120/240/600米，造成伤害量分别为6/12/26/58/118点不可豁免的音波伤害。</p><p>D+级：精神炸弹<br> 能造成念动属性伤害的小型炸弹。根据材料等级不同，花招使用射程分别为45/90/120/240/600米，造成伤害量分别为6/12/26/58/118点不可豁免的精神伤害。</p><p>D+级：原子火柴<br> 能造成核热属性伤害的小型炸弹。根据材料等级不同，花招使用射程分别为45/90/120/240/600米，造成伤害量分别为6/12/26/58/118点不可豁免的纯能量伤害。</p><p>D+级：红色炸弹<br> 能造成祝福属性伤害的小型炸弹。根据材料等级不同，花招使用射程分别为45/90/120/240/600米，造成伤害量分别为6/12/26/58/118点不可豁免的正能量伤害。</p><p>D+级：诅咒炸弹<br> 能造成咒怨属性伤害的小型炸弹。根据材料等级不同，花招使用射程分别为45/90/120/240/600米，造成伤害量分别为6/12/26/58/118点不可豁免的负能量伤害。</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',37)])])}const M=b(s,[["render",o]]);export{_ as __pageData,M as default};
